// --- CONFIGURAÇÃO DE LARGURA ---
// Aumentei para 17 para "caber" mais palavras na mesma linha
// e evitar contagem falsa de linhas extras.
const MAX_CHARS_POR_LINHA = 17; 

// Pega o texto do node anterior
const texto = $('Config Template - Qualificações1').item.json.titulo || "";

// --- O SIMULADOR DE QUEBRA (WORD WRAP) ---
const palavras = texto.split(' ');
let linhas = 1;
let charsNaLinhaAtual = 0;

for (let i = 0; i < palavras.length; i++) {
  const palavra = palavras[i];

  // Se é a primeira palavra da linha, só adiciona
  if (charsNaLinhaAtual === 0) {
    charsNaLinhaAtual = palavra.length;
  } 
  // Se a palavra + espaço cabe na linha atual, adiciona
  else if ((charsNaLinhaAtual + 1 + palavra.length) <= MAX_CHARS_POR_LINHA) {
    charsNaLinhaAtual += (1 + palavra.length);
  } 
  // Se não cabe, QUEBRA A LINHA e começa a contar na próxima
  else {
    linhas++;
    charsNaLinhaAtual = palavra.length;
  }
}

// --- RESULTADO ---
return {
  json: {
    ...items[0].json, // Passa todos os dados pra frente
    linhas_titulo_reais: linhas // O número mágico calculado
  }
};

