(() => {
  const data = $json;

  // --- 📏 CONFIGURAÇÕES (TITULO LONGO) ---
  const CANVAS_HEIGHT = 1080; 
  const MARGEM_ESQUERDA = "96px";
  const LARGURA_CAMADA = "456px"; 

  // GAPS (Mais respirados para muito texto)
  const GAP_PADRAO = 30;       // Aumentei para 30
  const GAP_BOTAO_EXTRA = 40;  // Afasta bem o botão

  // ALTURAS
  const H_ETIQUETA = 52;
  const H_BOTAO = 60;
  const H_LINHA_TITULO = 50; 
  const H_LINHA_FRASE = 35;  

  // QUEBRA DE LINHA
  const CHARS_TITULO = 12; 
  const CHARS_FRASE = 30; 

  // --- CÁLCULOS ---
  const tTitulo = data.titulo || "";
  const tFrase = data.frase || "";

  const linTitulo = Math.max(1, Math.ceil(tTitulo.length / CHARS_TITULO));
  const linFrase = Math.max(1, Math.ceil(tFrase.length / CHARS_FRASE));

  const hTituloTotal = linTitulo * H_LINHA_TITULO;
  const hFraseTotal = linFrase * H_LINHA_FRASE;

  // --- CENTRALIZAÇÃO VERTICAL ---
  const alturaBlocoInteiro = 
      H_ETIQUETA + GAP_PADRAO + 
      hTituloTotal + GAP_PADRAO + 
      hFraseTotal + GAP_PADRAO + GAP_BOTAO_EXTRA + 
      H_BOTAO;

  let y_atual = (CANVAS_HEIGHT - alturaBlocoInteiro) / 2;

  // IMPORTANTE: Texto longo sobe mais, mas nunca passa do teto (80px)
  if (y_atual < 80) y_atual = 80;

  // --- EMPILHAMENTO (CASCATA) ---

  // 1. Etiqueta
  const pos_etiqueta = y_atual;

  // 2. Título
  y_atual += H_ETIQUETA + GAP_PADRAO;
  const pos_titulo = y_atual;

  // 3. Frase
  y_atual += hTituloTotal + GAP_PADRAO;
  const pos_frase = y_atual;

  // 4. Botão
  y_atual += hFraseTotal + GAP_PADRAO + GAP_BOTAO_EXTRA;
  const pos_botao = y_atual;

  // --- JSON FINAL ---
  return {
    "template_uuid": data.template_id_placid,
    "layers": {
      "etiqueta": { "text": data.etiqueta, "position_x_absolute": MARGEM_ESQUERDA, "position_y_absolute": pos_etiqueta + 'px', "width": LARGURA_CAMADA },
      "titulo":   { "text": data.titulo,   "position_x_absolute": MARGEM_ESQUERDA, "position_y_absolute": pos_titulo + 'px',   "width": LARGURA_CAMADA },
      "frase":    { "text": data.frase,    "position_x_absolute": MARGEM_ESQUERDA, "position_y_absolute": pos_frase + 'px',    "width": LARGURA_CAMADA },
      "text-box": { "text": data['text-box'], "position_x_absolute": MARGEM_ESQUERDA, "position_y_absolute": pos_botao + 'px' },
      "box1":     { "position_x_absolute": MARGEM_ESQUERDA, "position_y_absolute": pos_botao + 'px' },
      "persona":  { "image": data.persona_image }
    }
  };
})()
}}

